(function() {
  const canvas = document.getElementById('related-posts-canvas');
  const container = document.getElementById('custom-related-gadget-container');

  function normalizeUrl(url) { return url.split(/[?#]/)[0].replace(/\/$/, ""); }
  const currentUrl = normalizeUrl(window.location.href);

  const allLinks = document.getElementsByTagName('a');
  const labelSet = new Set();
  for (let i = 0; i < allLinks.length; i++) {
    const href = allLinks[i].href;
    if (href.indexOf('/search/label/') !== -1) {
      const parts = href.split('/search/label/');
      const labelName = decodeURIComponent(parts[1].split('?')[0].split('#')[0]);
      if (labelName) labelSet.add(labelName);
    }
  }
  const labels = Array.from(labelSet);

  let labelIndex = 0;

  function fetchRelated(labelName) {
    if (!labelName) return;
    const script = document.createElement('script');
    script.src = "/feeds/posts/summary/-/" + encodeURIComponent(labelName) + "?alt=json-in-script&callback=processRelated&max-results=10";
    document.body.appendChild(script);
  }

  window.processRelated = function(data) {
    const entries = data.feed.entry || [];
    const filtered = entries.filter(e => {
      const link = e.link.find(l => l.rel === 'alternate').href;
      return normalizeUrl(link) !== currentUrl;
    });

    if (filtered.length > 0) {
      render(filtered);
    } else if (labelIndex < labels.length - 1) {
      labelIndex++;
      fetchRelated(labels[labelIndex]);
    } else {
      container.style.display = 'none';
    }
  };

  function render(posts) {
    let html = '';
    posts.slice(0, 6).forEach(entry => {
      const title = entry.title.$t;
      const link = entry.link.find(l => l.rel === 'alternate').href;
      const pub = entry.published.$t.substring(0, 10).replace(/-/g, '/');
      const thumb = entry.media$thumbnail 
        ? entry.media$thumbnail.url.replace('s72-c', 'w640-h360-p') 
        : 'https://via.placeholder.com/640x360?text=No+Image';

      html += `<a href="${link}" class="related-card-item"><div class="related-card-inner"><img src="${thumb}"><div class="related-card-content"><span class="related-card-date"><i class="fa-regular fa-calendar"></i>${pub}</span><div class="related-card-title">${title}</div></div></div></a>`;
    });
    canvas.innerHTML = html;
  }

  if (labels.length > 0) {
    fetchRelated(labels[0]);
  } else {
    container.style.display = 'none';
  }
})();
