(function() {
  var initMenu = function() {
    var nav = document.getElementById('PageList1');
    if (!nav) return;

    var topUl = nav.querySelector('ul');
    if (!topUl) return;

    // li を配列に変換（DOMを操作するので先にコピー）
    var allItems = Array.prototype.slice.call(topUl.querySelectorAll(':scope > li'));
    var currentParent = null;

    allItems.forEach(function(item) {
      var link = item.querySelector('a');
      if (!link) return;
      var text = link.textContent.trim();

      if (text.charAt(0) === '_') {
        // 子アイテム：直前の親に追加
        if (currentParent) {
          var sub = currentParent.querySelector('ul.sub-menu');
          if (!sub) {
            sub = document.createElement('ul');
            sub.className = 'sub-menu';
            currentParent.appendChild(sub);
            currentParent.classList.add('has-sub');

            // 親ラベルクリック → サブメニュー開閉
            var parentLink = currentParent.querySelector('a');
            parentLink.addEventListener('click', function(e) {
              e.preventDefault();
              e.stopPropagation();
              // 他を閉じる
              var openItems = document.querySelectorAll('#PageList1 li.has-sub.open');
              for (var i = 0; i < openItems.length; i++) {
                if (openItems[i] !== currentParent) {
                  openItems[i].classList.remove('open');
                }
              }
              currentParent.classList.toggle('open');
            });
          }
          // 先頭の「_」を取り除く
          link.textContent = text.replace(/^_+/, '');
          sub.appendChild(item);
        }
      } else {
        // 通常アイテム → 次の親候補
        currentParent = item;
      }
    });

    // 準備完了 → 一斉に表示
    topUl.classList.add('menu-ready');

    // メニュー外クリックで全閉じ
    document.addEventListener('click', function() {
      var openItems = document.querySelectorAll('#PageList1 li.has-sub.open');
      for (var i = 0; i < openItems.length; i++) {
        openItems[i].classList.remove('open');
      }
    });
  };

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', initMenu);
  } else {
    initMenu();
  }
})();
//

b:if.script:
//
  var toc_options = {
    target: ["h2", "h3", "h4"],
    autoNumber:  true,
    condTargetCount: 2,
    postBodySelector: ".post-body"
  };

  ;(function (window) {
    var id_seq = 0;

    document.addEventListener('DOMContentLoaded', function () {
      var rootElement = document.querySelector(toc_options.postBodySelector);
      // 挿入先となるターゲット（id="toc" または class="toc"）を探す
      var tocPlaceholder = document.getElementById('toc') || document.querySelector('.toc');

      // 記事本文がない、または目次用タグが記述されていない場合は実行しない
      if (!rootElement || !tocPlaceholder) { return; }

      if (toc_options.target.length == 0) return;

      var rootContent = searchHeadLine(toc_options, rootElement);

      if (rootContent.children.length >= toc_options.condTargetCount) {
        var wrap = createElement(rootContent);
        // 指定されたタグの中に目次を流し込む
        tocPlaceholder.innerHTML = ''; 
        tocPlaceholder.appendChild(wrap);
      }
    });

    function searchHeadLine(toc_options, rootElement) {
      var count = toc_options.target.length;
      var fn = function (index, element, parentContent) {
        var currentTarget = toc_options.target[index];
        var nextTarget = index < count - 1 ? toc_options.target[index + 1] : "";
        var id = "toc_headline_" + (++id_seq);
        var content = createItem(currentTarget, text(element), index + 1, id);
        parentContent.children.push(content);
        element.id = id;
        var el = next(element);
        if (nextTarget == "") { return; }
        var prevTarget = "";
        for(var i = index; i >= 0; i--) { prevTarget += (toc_options.target[i] + ",");}
        while (true) {
          if (el == null || typeof el === "undefined") break;
          if (tagName(el) == currentTarget) break;
          if (tagName(el) == nextTarget) {
            fn(index + 1, el, content);
          } else {
            var nextElements = el.querySelectorAll(prevTarget + nextTarget);
            var breakFlg = false;
            for (var i = 0; i < nextElements.length; i++) {
              if (tagName(nextElements[i]) != nextTarget) {
                exitFlg = true;
                break;
              }
              fn(index + 1, nextElements[i], content);
            }
            if (breakFlg) break;
          }
          var el = next(el);
        }
      };
      var rootContent = createItem("ROOT", "", 0);
      var elements = rootElement.getElementsByTagName(toc_options.target[0]);
      for (var i = 0; i < elements.length; i++) {
        fn(0, elements[i], rootContent, "");
      }
      return rootContent;
    }

    function createElement(rootContent) {
      var wrap = document.createElement("div");
      wrap.classList.add("custom-toc");

      var p = document.createElement("p");
      var span1 = document.createElement("span");
      var span2 = document.createElement("span");
      var span3 = document.createElement("span");
      span2.classList.add("b-toc-show-wrap");
      span3.classList.add("b-toc-show-wrap");
      var a = document.createElement("a");
      span1.innerText = "目次";
      span2.innerText = "[";
      span3.innerText = "]";
      a.href = "javascript:void(0);";
      p.appendChild(span1);
      p.appendChild(span2);
      p.appendChild(a);
      p.appendChild(span3);

      var toggleToc = function (state) {
        var isHide = wrap.classList.contains("hide");
        var s = (typeof state === "boolean") ? state : isHide;
        if (s) {
          a.innerText = "非表示";
          wrap.classList.remove("hide");
        } else {
          a.innerText = "表示";
          wrap.classList.add("hide");
        }
      };
      a.addEventListener('click', toggleToc);
      toggleToc(true); // 初期状態で表示

      var ul = document.createElement("ul");
      ul.classList.add("toc-content");
      rootContent.children.forEach(function (content, index) {
        createContentItemElement(ul, content, (index + 1) + "");
      });
      wrap.appendChild(p);
      wrap.appendChild(ul);
      return wrap;
    }

    function createContentItemElement(ul, content, no) {
      var li = document.createElement("li");
      li.classList.add("toc-list-item");
      li.classList.add("toc-item-" + content.tagName);
      var a = document.createElement("a");
      ul.style.paddingLeft = 0;
      a.href = "#" + content.id;
      smoothScroll(a);
      if (toc_options.autoNumber) {
        var spanNm = document.createElement("span");
        spanNm.classList.add("toc-number");
        spanNm.innerText = no + ".";
      }
      var spanText = document.createElement("span");
      spanText.classList.add("toc-text");
      spanText.innerText = content.text;
      if (toc_options.autoNumber) a.appendChild(spanNm);
      a.appendChild(spanText);
      li.appendChild(a);
      ul.appendChild(li);
      if (content.children.length > 0) {
        var childUl = document.createElement("ul");
        childUl.classList.add("toc-sub-list");
        li.appendChild(childUl);
        content.children.forEach(function (childContent, index) {
          createContentItemElement(childUl, childContent, no + "." + (index + 1));
        });
      }
    }

    function smoothScroll(a) {
      a.addEventListener('click', (e) => {
        e.preventDefault();
        let href = a.getAttribute('href');
        let targetElement = document.getElementById(href.replace('#', ''));
        if(targetElement){
          const rect = targetElement.getBoundingClientRect().top;
          const offset = window.pageYOffset;
          const target = rect + offset - 0;
          window.scrollTo({ top: target, behavior: 'smooth', });
        }
      });
    }

    function createItem(tagName, text, nestLevel, id) {
      return { tagName: tagName, text: text, children: [], nestLevel: nestLevel, id: id};
    }
    function text(element) { return element.innerText; }
    function next(element) { return element.nextElementSibling; }
    function tagName(element) { return element.tagName.toLowerCase(); }
    function parentElement(element) { return element.parentNode; }
    function before(element, insertElement) {
      var parent = parentElement(element);
      if (parent != null) { parent.insertBefore(insertElement, element); }
    }
  })(window);
