(function() {

  /* =============================================
     ★ キャラクター設定
     名前をキーにして画像URLと表示名を登録してください
     ============================================= */
  var CHAT_CHARS = {
    'パンダくん': {
      img: 'https://placehold.jp/80x80.png?text=Panda',
      name: 'パンダくん',
      color: '#da9e5b',      // 吹き出し色
      borderColor: '#da9e5b' // アイコン枠色
    },
    '太郎': {
      img: 'https://placehold.jp/80x80.png?text=Taro',
      name: '太郎',
      color: '#85e3ff',
      borderColor: '#85e3ff'
    }
    /* ↑ カンマで区切って追加できます
    ,'キャラ名': {
      img: '画像URL',
      name: '表示名',
      color: '吹き出し色',
      borderColor: 'アイコン枠色'
    }
    */
  };
  /* ============================================= */

  var DEFAULT_IMG = 'https://placehold.jp/80x80.png?text=icon';
  var DEFAULT_COLOR = '#aaaaaa';

  function buildBalloon(dir, char, serif) {
    var c = CHAT_CHARS[char] || {};
    var img    = c.img         || DEFAULT_IMG;
    var name   = c.name        || char || '';
    var color  = c.color       || DEFAULT_COLOR;
    var border = c.borderColor || color;

    var iconStyle  = 'border: solid 4px ' + border + ';';
    var serifStyle = 'background:' + color + ';';
    var arrowStyle = 'border-right-color:' + color + ';';

    var iconHtml = '<img src="' + img + '" alt="' + name + '" style="' + iconStyle + '">'
                 + (name ? '<p>' + name + '</p>' : '');

    if (dir === 'left') {
      return '<div class="balloon-simple">'
        + '<div class="icon-left">' + iconHtml + '</div>'
        + '<div class="balloon"><div class="serif-left" style="' + serifStyle + '">'
        + '<p>' + serif + '</p></div></div></div>';
    } else {
      return '<div class="balloon-simple">'
        + '<div class="icon-right">' + iconHtml + '</div>'
        + '<div class="balloon"><div class="serif-right" style="' + serifStyle + '">'
        + '<p>' + serif + '</p></div></div></div>';
    }
  }

  function convertBalloons() {
    var bodies = document.querySelectorAll('.post-body, #single-content');
    bodies.forEach(function(body) {
      var html = body.innerHTML;

      // [chat-left char="名前"]セリフ[/chat-left]
      // [chat-left img="URL" name="名前"]セリフ[/chat-left]  ← 直接指定も可
      html = html.replace(
        /\[chat-left(?:\s+char=["']([^"'<>]*)["'])?(?:\s+img=["']([^"'<>]*)["'])?(?:\s+name=["']([^"'<>]*)["'])?\]([\s\S]*?)\[\/chat-left\]/g,
        function(m, charKey, imgDirect, nameDirect, serif) {
          if (charKey) return buildBalloon('left', charKey, serif.trim());
          // 直接指定の場合
          var c = { img: imgDirect, name: nameDirect, color: '#da9e5b', borderColor: '#da9e5b' };
          CHAT_CHARS['__tmp'] = c;
          return buildBalloon('left', '__tmp', serif.trim());
        }
      );

      // [chat-right char="名前"]セリフ[/chat-right]
      html = html.replace(
        /\[chat-right(?:\s+char=["']([^"'<>]*)["'])?(?:\s+img=["']([^"'<>]*)["'])?(?:\s+name=["']([^"'<>]*)["'])?\]([\s\S]*?)\[\/chat-right\]/g,
        function(m, charKey, imgDirect, nameDirect, serif) {
          if (charKey) return buildBalloon('right', charKey, serif.trim());
          var c = { img: imgDirect, name: nameDirect, color: '#85e3ff', borderColor: '#85e3ff' };
          CHAT_CHARS['__tmp'] = c;
          return buildBalloon('right', '__tmp', serif.trim());
        }
      );

      body.innerHTML = html;
    });
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', convertBalloons);
  } else {
    convertBalloons();
  }
})();
