(function() {
  const cleanup = () => {
    const container = document.getElementById('custom-breadcrumbs');
    if (!container) return;

    const units = Array.from(container.querySelectorAll('.bc-item-unit'));

    // 1. まず「#なしの正しいラベル」があるか探す
    const validLabel = units.find(unit => {
      const link = unit.querySelector('a');
      return link && !link.getAttribute('href').includes('%23');
    });

    let foundOne = false;

    units.forEach(unit => {
      const link = unit.querySelector('a');
      if (!link) return;

      const isHash = link.getAttribute('href').includes('%23');

      // 【判定ロジック】
      // A. 他に正しいラベルがあるのに、これは #タグ である → 削除
      // B. 既に1つ表示済みである → 削除
      if ((validLabel && isHash) || foundOne) {
        unit.parentNode.removeChild(unit);
      } 
      // C. それ以外（「最初の正しいラベル」または「#しかない時の最初の#」） → 残す
      else {
        foundOne = true;
        const sep = unit.querySelector('.bc-sep');
        if (sep) sep.parentNode.removeChild(sep);
      }
    });
  };

  window.addEventListener('DOMContentLoaded', cleanup);
  setTimeout(cleanup, 500); 
})();
