(function() {
  /**
   * true  = 初回読み込み時のみ「閉じた」状態にする
   * false = 標準（最新を展開）のまま
   */
  const CONFIG_COLLAPSE_INIT = true; 
  let isFirstRun = true; // 初回実行判定フラグ

  const updateArchive = () => {
    const archiveList = document.getElementById('BlogArchive1_ArchiveList');
    if (!archiveList) return;

    // 1. 日付フォーマットの変換 (2026 3月)
    const archiveLinks = archiveList.querySelectorAll('.post-count-link');
    archiveLinks.forEach(link => {
      const text = link.textContent.trim();
      const match = text.match(/^(\d+月)\s+(\d{4})$/);
      if (match) {
        link.textContent = `${match[2]} ${match[1]}`;
      }
    });

    // 2. 初回のみ「閉じる」処理を実行
    if (CONFIG_COLLAPSE_INIT && isFirstRun) {
      const expandedItems = archiveList.querySelectorAll('.archivedate.expanded');
      expandedItems.forEach(item => {
        item.classList.remove('expanded');
        item.classList.add('collapsed');

        const zippy = item.querySelector('.zippy');
        if (zippy) {
          zippy.classList.remove('toggle-open');
          zippy.innerHTML = '&#9658;&nbsp;'; // ►
        }
      });
      isFirstRun = false; // 二回目以降（クリック時など）はこのブロックを通さない
    }
  };

  // 実行
  updateArchive();
  setTimeout(updateArchive, 200);

  // クリック時は「フォーマット変換」のみを動かす
  document.addEventListener('click', (e) => {
    const toggle = e.target.closest('.toggle');
    if (toggle) {
      // ユーザーのクリックによる展開を邪魔しないよう、少し遅らせて文字だけ整える
      setTimeout(() => {
        isFirstRun = false; 
        updateArchive();
      }, 100);
    }
  }, true);
})();
